#[derive(Debug, Clone)]
enum Op {
    AddUser(usize),
    AddLp(usize),
    ReclaimEmptyAccount(usize),
    CloseAccount(usize),
    Deposit(usize, u128),
    Withdraw(usize, u128),
    TopUpInsurance(u128),
    DepositFeeCredits(usize, u128),
    ConvertReleasedPnl(usize, u128),
    ExecuteTrade(usize, usize, i128, u64),
    LiquidateCase0(usize),
    LiquidateCase1(usize),
    LiquidateOtherwise(usize),
    SettleAccount(usize),
    TriggerAdl,
    CompleteDrain,
    Reset,
}

fn arb_op() -> impl Strategy<Value = Op> {
    prop_oneof![
        (0usize..=usize::MAX).prop_map(|v| Op::AddUser(v)),
        (0usize..=usize::MAX).prop_map(|v| Op::AddLp(v)),
        (0usize..=usize::MAX).prop_map(|v| Op::ReclaimEmptyAccount(v)),
        (0usize..=usize::MAX).prop_map(|v| Op::CloseAccount(v)),
        (0usize..=usize::MAX, 0u128..=u128::MAX).prop_map(|(i, amount)| Op::Deposit(i, amount)),
        (0usize..=usize::MAX, 0u128..=u128::MAX).prop_map(|(i, amount)| Op::Withdraw(i, amount)),
        (0u128..=u128::MAX).prop_map(|v| Op::TopUpInsurance(v)),
        (0usize..=usize::MAX, 0u128..=u128::MAX).prop_map(|(i, amount)| Op::DepositFeeCredits(i, amount)),
        (0usize..=usize::MAX, 0u128..=u128::MAX).prop_map(|(i, x)| Op::ConvertReleasedPnl(i, x)),
        (0usize..=usize::MAX, 0usize..=usize::MAX, 0i128..=i128::MAX, 0u64..=u64::MAX).prop_map(|(a, b, size_q, exec_price)| Op::ExecuteTrade(a, b, size_q, exec_price)),
        (0usize..=usize::MAX).prop_map(|v| Op::LiquidateCase0(v)),
        (0usize..=usize::MAX).prop_map(|v| Op::LiquidateCase1(v)),
        (0usize..=usize::MAX).prop_map(|v| Op::LiquidateOtherwise(v)),
        (0usize..=usize::MAX).prop_map(|v| Op::SettleAccount(v)),
        Just(Op::TriggerAdl),
        Just(Op::CompleteDrain),
        Just(Op::Reset),
    ]
}

fn apply_op(s: &mut State, op: &Op) -> bool {
    match op {
        Op::AddUser(i) => add_user(s, *i),
        Op::AddLp(i) => add_lp(s, *i),
        Op::ReclaimEmptyAccount(i) => reclaim_empty_account(s, *i),
        Op::CloseAccount(i) => close_account(s, *i),
        Op::Deposit(i, amount) => deposit(s, *i, *amount),
        Op::Withdraw(i, amount) => withdraw(s, *i, *amount),
        Op::TopUpInsurance(amount) => top_up_insurance(s, *amount),
        Op::DepositFeeCredits(i, amount) => deposit_fee_credits(s, *i, *amount),
        Op::ConvertReleasedPnl(i, x) => convert_released_pnl(s, *i, *x),
        Op::ExecuteTrade(a, b, size_q, exec_price) => execute_trade(s, *a, *b, *size_q, *exec_price),
        Op::LiquidateCase0(i) => liquidate_case_0(s, *i),
        Op::LiquidateCase1(i) => liquidate_case_1(s, *i),
        Op::LiquidateOtherwise(i) => liquidate_otherwise(s, *i),
        Op::SettleAccount(i) => settle_account(s, *i),
        Op::TriggerAdl => trigger_adl(s),
        Op::CompleteDrain => complete_drain(s),
        Op::Reset => reset(s),
    }
}

fn assert_all_properties(s: &State, context: &str) {
    assert!(conservation(s), "{} violated: conservation", context);
    assert!(vault_bounded(s), "{} violated: vault_bounded", context);
    assert!(account_solvent(s), "{} violated: account_solvent", context);
}

#[derive(Debug, Clone, Copy, PartialEq)]
enum Lifecycle {
    Active,
    Draining,
    Resetting,
}

fn lifecycle_transition(current: Lifecycle, op: &Op) -> Option<Lifecycle> {
    match (current, op) {
        (Lifecycle::Active, Op::AddUser(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::AddLp(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::ReclaimEmptyAccount(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::CloseAccount(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::Deposit(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::Withdraw(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::TopUpInsurance(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::DepositFeeCredits(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::ConvertReleasedPnl(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::ExecuteTrade(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::LiquidateCase0(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::LiquidateCase1(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::LiquidateOtherwise(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::SettleAccount(..)) => Some(Lifecycle::Active),
        (Lifecycle::Active, Op::TriggerAdl) => Some(Lifecycle::Draining),
        (Lifecycle::Draining, Op::CompleteDrain) => Some(Lifecycle::Resetting),
        (Lifecycle::Resetting, Op::Reset) => Some(Lifecycle::Active),
        _ => None, // transition not allowed in this state
    }
}

proptest! {
    #![proptest_config(ProptestConfig::with_cases(256))]
    #[test]
    fn state_machine_sequence(ops in proptest::collection::vec(arb_op(), 1..20)) {
        let mut s = State {
            authority: [0u8; 32],
            V: 0,
            I: 0,
            F: 0,
            accounts: [Account::default(); 1024],
            status: Status::Active,
        };
        let mut lifecycle = Lifecycle::Active;
        let mut initialized = false;
        for (i, op) in ops.iter().enumerate() {
            let next_lifecycle = lifecycle_transition(lifecycle, op);
            if next_lifecycle.is_none() {
                continue; // skip ops not valid in current lifecycle state
            }
            if apply_op(&mut s, op) {
                if let Some(next) = next_lifecycle {
                    lifecycle = next;
                }
                // Check all properties after each successful transition
                prop_assert!(conservation(&s),
                    "conservation violated after op {:?} (step {})", op, i);
                prop_assert!(vault_bounded(&s),
                    "vault_bounded violated after op {:?} (step {})", op, i);
                prop_assert!(account_solvent(&s),
                    "account_solvent violated after op {:?} (step {})", op, i);
            }
        }
    }
}
